// Template: pair with target sum in a SORTED array. O(n) time, O(1) space.
function pairSum(sortedNums, target) {
  let lo = 0, hi = sortedNums.length - 1;
  while (lo < hi) {
    const sum = sortedNums[lo] + sortedNums[hi];
    if (sum === target) return [lo, hi];
    if (sum < target) lo++;   // need a bigger sum
    else hi--;                // need a smaller sum
  }
  return [-1, -1];
}

function threeSum(nums) {
  nums.sort((a, b) => a - b);
  const res = [];
  for (let i = 0; i < nums.length - 2; i++) {
    if (i > 0 && nums[i] === nums[i - 1]) continue;     // skip dup anchor
    let lo = i + 1, hi = nums.length - 1;
    while (lo < hi) {
      const sum = nums[i] + nums[lo] + nums[hi];
      if (sum === 0) {
        res.push([nums[i], nums[lo], nums[hi]]);
        while (lo < hi && nums[lo] === nums[lo + 1]) lo++; // skip dups
        while (lo < hi && nums[hi] === nums[hi - 1]) hi--;
        lo++; hi--;
      } else if (sum < 0) lo++;
      else hi--;
    }
  }
  return res; // O(n^2) time, O(1) extra (excluding output)
}

// Template: longest substring with NO repeating characters. O(n) time.
function longestUniqueSubstring(s) {
  const lastSeen = new Map(); // char -> last index
  let left = 0, best = 0;
  for (let right = 0; right < s.length; right++) {
    const c = s[right];
    // If c is in the window, jump left past its previous occurrence.
    if (lastSeen.has(c) && lastSeen.get(c) >= left) {
      left = lastSeen.get(c) + 1;
    }
    lastSeen.set(c, right);
    best = Math.max(best, right - left + 1);
  }
  return best;
}

// Fixed-size window: max sum of any k consecutive elements. O(n).
function maxSumK(nums, k) {
  let windowSum = 0, best = -Infinity;
  for (let right = 0; right < nums.length; right++) {
    windowSum += nums[right];
    if (right >= k - 1) {
      best = Math.max(best, windowSum);
      windowSum -= nums[right - k + 1]; // drop the leftmost
    }
  }
  return best;
}

// Detect a cycle in a linked list. O(n) time, O(1) space.
function hasCycle(head) {
  let slow = head, fast = head;
  while (fast && fast.next) {
    slow = slow.next;        // +1
    fast = fast.next.next;   // +2
    if (slow === fast) return true; // they met inside the loop
  }
  return false;              // fast hit the end -> no cycle
}

// Find the node where the cycle begins, or null. O(n) time, O(1) space.
function cycleStart(head) {
  let slow = head, fast = head;
  while (fast && fast.next) {
    slow = slow.next;
    fast = fast.next.next;
    if (slow === fast) {            // phase 1: meeting point found
      let p = head;
      while (p !== slow) {          // phase 2: walk both at +1
        p = p.next;
        slow = slow.next;
      }
      return p;                     // entrance of the cycle
    }
  }
  return null;
}

// BFS level-order traversal of a binary tree -> array of levels. O(n).
function levelOrder(root) {
  if (!root) return [];
  const levels = [];
  let queue = [root];
  while (queue.length) {
    const level = [], next = [];
    for (const node of queue) {
      level.push(node.val);
      if (node.left) next.push(node.left);
      if (node.right) next.push(node.right);
    }
    levels.push(level);
    queue = next;            // advance to the next level
  }
  return levels;
}

// DFS on a graph: count connected components. O(V + E).
function countComponents(n, edges) {
  const adj = Array.from({ length: n }, () => []);
  for (const [a, b] of edges) { adj[a].push(b); adj[b].push(a); }
  const seen = new Array(n).fill(false);
  let count = 0;
  const dfs = (u) => {
    seen[u] = true;
    for (const v of adj[u]) if (!seen[v]) dfs(v);
  };
  for (let i = 0; i < n; i++) {
    if (!seen[i]) { count++; dfs(i); }  // new component
  }
  return count;
}

// Template: all subsets (the power set). O(2^n) subsets, O(n) each to copy.
function subsets(nums) {
  const res = [];
  const backtrack = (start, path) => {
    res.push([...path]);                 // every node is a valid subset
    for (let i = start; i < nums.length; i++) {
      path.push(nums[i]);                // choose
      backtrack(i + 1, path);            // explore (i+1 avoids reuse/dupes)
      path.pop();                        // un-choose (backtrack)
    }
  };
  backtrack(0, []);
  return res;
}

// Permutations. O(n!) leaves. 'used' marks elements already in the path.
function permute(nums) {
  const res = [], used = new Array(nums.length).fill(false);
  const backtrack = (path) => {
    if (path.length === nums.length) { res.push([...path]); return; }
    for (let i = 0; i < nums.length; i++) {
      if (used[i]) continue;
      used[i] = true; path.push(nums[i]);   // choose
      backtrack(path);                        // explore
      path.pop(); used[i] = false;            // un-choose
    }
  };
  backtrack([]);
  return res;
}

// Top-down (memoized) coin change: fewest coins to make 'amount'. 
// O(amount * coins) time and space.
function coinChangeTopDown(coins, amount) {
  const memo = new Map();
  const dp = (rem) => {
    if (rem === 0) return 0;
    if (rem < 0) return Infinity;            // invalid path
    if (memo.has(rem)) return memo.get(rem);
    let best = Infinity;
    for (const c of coins) best = Math.min(best, 1 + dp(rem - c));
    memo.set(rem, best);
    return best;
  };
  const ans = dp(amount);
  return ans === Infinity ? -1 : ans;
}

// Bottom-up coin change: same recurrence, iterative table.
// dp[a] = fewest coins to make amount a. O(amount * coins).
function coinChangeBottomUp(coins, amount) {
  const dp = new Array(amount + 1).fill(Infinity);
  dp[0] = 0;                                  // base case: 0 coins for 0
  for (let a = 1; a <= amount; a++) {
    for (const c of coins) {
      if (c <= a && dp[a - c] + 1 < dp[a]) {
        dp[a] = dp[a - c] + 1;
      }
    }
  }
  return dp[amount] === Infinity ? -1 : dp[amount];
}

// Classic: index of target in a sorted array, or -1. O(log n).
function binarySearch(nums, target) {
  let lo = 0, hi = nums.length - 1;
  while (lo <= hi) {
    const mid = lo + ((hi - lo) >> 1);   // avoids overflow in other langs
    if (nums[mid] === target) return mid;
    if (nums[mid] < target) lo = mid + 1;
    else hi = mid - 1;
  }
  return -1;
}

// Lower bound: first index with nums[i] >= target (the 'leftmost' variant).
// Returns nums.length if no such element. O(log n).
function lowerBound(nums, target) {
  let lo = 0, hi = nums.length;          // half-open [lo, hi)
  while (lo < hi) {
    const mid = lo + ((hi - lo) >> 1);
    if (nums[mid] < target) lo = mid + 1; // mid too small, discard left half
    else hi = mid;                        // mid is a candidate, keep it
  }
  return lo;
}

function shipWithinDays(weights, days) {
  const feasible = (cap) => {
    let need = 1, cur = 0;
    for (const w of weights) {
      if (cur + w > cap) { need++; cur = 0; } // start a new day
      cur += w;
    }
    return need <= days;
  };
  let lo = Math.max(...weights);           // must fit the heaviest item
  let hi = weights.reduce((a, b) => a + b, 0); // all in one day
  while (lo < hi) {
    const mid = lo + ((hi - lo) >> 1);
    if (feasible(mid)) hi = mid;            // try smaller
    else lo = mid + 1;                       // need bigger
  }
  return lo; // O(n log(sum)) time
}

// Minimal binary min-heap (enough for top-K). All ops O(log n).
class MinHeap {
  constructor() { this.a = []; }
  size() { return this.a.length; }
  peek() { return this.a[0]; }
  push(x) {
    const a = this.a; a.push(x);
    let i = a.length - 1;
    while (i > 0) {
      const p = (i - 1) >> 1;
      if (a[p] <= a[i]) break;
      [a[p], a[i]] = [a[i], a[p]]; i = p;   // sift up
    }
  }
  pop() {
    const a = this.a, top = a[0], last = a.pop();
    if (a.length) {
      a[0] = last; let i = 0;
      while (true) {
        const l = 2 * i + 1, r = 2 * i + 2; let s = i;
        if (l < a.length && a[l] < a[s]) s = l;
        if (r < a.length && a[r] < a[s]) s = r;
        if (s === i) break;
        [a[s], a[i]] = [a[i], a[s]]; i = s;  // sift down
      }
    }
    return top;
  }
}

// kth largest element. O(n log k) time, O(k) space.
function kthLargest(nums, k) {
  const h = new MinHeap();
  for (const x of nums) {
    h.push(x);
    if (h.size() > k) h.pop();   // evict smallest, keep k largest
  }
  return h.peek();               // smallest of the k largest = kth largest
}

// Build prefix sums, then answer range queries in O(1).
function prefix(nums) {
  const P = new Array(nums.length + 1).fill(0);
  for (let i = 0; i < nums.length; i++) P[i + 1] = P[i] + nums[i];
  return P; // sum of nums[l..r] inclusive = P[r + 1] - P[l]
}

// Number of contiguous subarrays summing to k. O(n) time, O(n) space.
function subarraySum(nums, k) {
  const seen = new Map([[0, 1]]); // prefix sum 0 occurs once (empty prefix)
  let running = 0, count = 0;
  for (const x of nums) {
    running += x;
    // a start point exists where prefix == running - k
    count += seen.get(running - k) ?? 0;
    seen.set(running, (seen.get(running) ?? 0) + 1);
  }
  return count;
}

// Merge all overlapping intervals. O(n log n) for the sort, O(n) pass.
function mergeIntervals(intervals) {
  if (intervals.length === 0) return [];
  intervals.sort((a, b) => a[0] - b[0]);   // by start
  const merged = [intervals[0].slice()];
  for (let i = 1; i < intervals.length; i++) {
    const last = merged[merged.length - 1];
    const [s, e] = intervals[i];
    if (s <= last[1]) {
      last[1] = Math.max(last[1], e);       // overlap -> extend end
    } else {
      merged.push([s, e]);                  // disjoint -> new interval
    }
  }
  return merged;
}
// merge([[1,3],[2,6],[8,10],[15,18]]) -> [[1,6],[8,10],[15,18]]

