function lengthOfLongestSubstring(s) {
  const lastSeen = new Map(); // char -> most recent index
  let left = 0;               // left edge of the current window
  let best = 0;

  for (let right = 0; right < s.length; right++) {
    const c = s[right];
    // If c is already inside the window, jump left to just past it.
    // The >= left guard prevents moving left backwards on stale entries.
    if (lastSeen.has(c) && lastSeen.get(c) >= left) {
      left = lastSeen.get(c) + 1;
    }
    lastSeen.set(c, right);
    best = Math.max(best, right - left + 1); // current window length
  }
  return best;
}

// Quick checks:
// lengthOfLongestSubstring('abcabcbb') === 3
// lengthOfLongestSubstring('bbbbb')    === 1
// lengthOfLongestSubstring('pwwkew')   === 3
// lengthOfLongestSubstring('')         === 0
// lengthOfLongestSubstring('au')       === 2  (stale 'a' not re-counted)

function subsets(nums) {
  const res = [];

  const backtrack = (start, path) => {
    res.push([...path]);            // every prefix path is a valid subset
    for (let i = start; i < nums.length; i++) {
      path.push(nums[i]);           // choose nums[i]
      backtrack(i + 1, path);       // explore with elements AFTER i only
      path.pop();                   // un-choose (restore state for sibling)
    }
  };

  backtrack(0, []);
  return res;
}

// subsets([1,2,3]) ->
// [], [1], [1,2], [1,2,3], [1,3], [2], [2,3], [3]   (all 8, order varies)
// subsets([])  -> [[]]
// subsets([7]) -> [[], [7]]

function hasCycle(head) {
  let slow = head;
  let fast = head;

  // fast moves twice as fast; if it can take two steps, the list continues.
  while (fast !== null && fast.next !== null) {
    slow = slow.next;        // +1
    fast = fast.next.next;   // +2
    if (slow === fast) {     // pointers collided inside the loop
      return true;
    }
  }
  return false;              // fast reached the end -> acyclic
}

